(function () {
  function style() { if (document.getElementById('iet-style')) return; var s = document.createElement('style'); s.id = 'iet-style'; s.textContent = '.iet-wrap{border:1px solid #e5e7eb;border-radius:12px;padding:16px;background:#fff;margin:14px 0}.iet-checks{display:flex;gap:10px;flex-wrap:wrap}.iet-checks label{padding:8px 12px;border:1px solid #cbd5e1;border-radius:999px;background:#f8fafc}.iet-venn{position:relative;width:260px;height:210px;margin:16px auto}.iet-c{position:absolute;width:132px;height:132px;border-radius:50%;opacity:.42;border:2px solid}.iet-a{left:28px;top:18px;background:#93c5fd;border-color:#007bff}.iet-b{right:28px;top:18px;background:#86efac;border-color:#28a745}.iet-c3{left:64px;bottom:10px;background:#fcd34d;border-color:#f4a261}.iet-dot{position:absolute;left:121px;top:92px;width:18px;height:18px;border-radius:50%;background:#dc3545;box-shadow:0 0 0 5px rgba(220,53,69,.18);transition:all .2s ease}.iet-out{padding:10px;border-radius:8px;background:#f8f9fa;border-left:4px solid #007bff}.iet-term{font-weight:700;color:#495057}'; document.head.appendChild(s); }
  function mount(host) { if (!host || host.dataset.ietMounted) return; host.dataset.ietMounted = '1'; style(); host.innerHTML = '<div class="iet-wrap"><h4>Bù trừ cho một phần tử</h4><div class="iet-checks"><label><input type="checkbox" value="A" checked> A</label><label><input type="checkbox" value="B" checked> B</label><label><input type="checkbox" value="C"> C</label></div><div class="iet-venn"><div class="iet-c iet-a"></div><div class="iet-c iet-b"></div><div class="iet-c iet-c3"></div><div class="iet-dot" title="phần tử đang xét"></div></div><div class="iet-out" aria-live="polite"></div></div>'; var out = host.querySelector('.iet-out'), dot = host.querySelector('.iet-dot'); function render() { var vals = Array.prototype.slice.call(host.querySelectorAll('input:checked')).map(function (x) { return x.value; }); var singles = vals.length, pairs = vals.length >= 2 ? vals.length * (vals.length - 1) / 2 : 0, triple = vals.length === 3 ? 1 : 0, net = singles - pairs + triple; var positions = { '': [121, 92], A: [74, 70], B: [168, 70], C: [121, 150], AB: [121, 64], AC: [96, 112], BC: [146, 112], ABC: [121, 102] }; var p = positions[vals.join('')] || positions[vals.sort().join('')] || positions['']; dot.style.left = p[0] + 'px'; dot.style.top = p[1] + 'px'; out.innerHTML = 'Phần tử thuộc <span class="iet-term">' + (vals.length ? vals.join(' ∩ ') : 'không tập nào') + '</span>.<br>Được cộng <strong>' + singles + '</strong> lần trong |A|+|B|+|C|, bị trừ <strong>' + pairs + '</strong> lần ở các giao đôi, được cộng lại <strong>' + triple + '</strong> lần ở giao ba → net count = <strong>' + net + '</strong>.'; } host.addEventListener('change', render); render(); }
  function safeMount(host) { try { mount(host); } catch (err) { if (host) host.innerHTML = '<div class="iet-out">Không thể tải demo bù trừ. Hãy tải lại trang.</div>'; } }
  document.addEventListener('DOMContentLoaded', function () { Array.prototype.forEach.call(document.querySelectorAll('[data-demo="inclusion-exclusion-toggle"]'), safeMount); });
})();
